async function main() {
  let updatedCount = 0;
  let errorCount = 0;
  let totalDescWords = 0;
  let minDescWords = Infinity;
  let maxDescWords = 0;
  let totalMetaLength = 0;

  for (const item of updates) {
    try {
      const result = await prisma.product.update({
        where: { id: item.id },
        data: {
          description: item.description,
          metaDescription: item.metaDescription
        }
      });

      const descWords = item.description.trim().split(/\s+/).length;
      const metaLen = item.metaDescription.length;
      totalDescWords += descWords;
      totalMetaLength += metaLen;
      if (descWords < minDescWords) minDescWords = descWords;
      if (descWords > maxDescWords) maxDescWords = descWords;

      console.log(`✅ [${descWords} words | ${metaLen} chars] Updated: ${result.slug}`);
      updatedCount++;
    } catch (error) {
      console.error(`❌ Error updating ${item.id}: ${error.message}`);
      errorCount++;
    }
  }

  const avgDescWords = updatedCount > 0 ? (totalDescWords / updatedCount).toFixed(1) : 0;
  const avgMetaLen = updatedCount > 0 ? (totalMetaLength / updatedCount).toFixed(1) : 0;

  console.log('\n--- BATCH R6A-R6F SUMMARY ---');
  console.log(`Total products updated: ${updatedCount}`);
  console.log(`Errors: ${errorCount}`);
  console.log(`Average description word count: ${avgDescWords}`);
  console.log(`Min description word count: ${minDescWords === Infinity ? 0 : minDescWords}`);
  console.log(`Max description word count: ${maxDescWords}`);
  console.log(`Average meta description length: ${avgMetaLen} chars`);
  console.log('--- END SUMMARY ---');
}

main().then(() => prisma.$disconnect());
